                locale?: string | null;
                /** @description Optional WeChat user id for dual-端 sync push. When provided, the AI reply is pushed to this WeChat user after stream completion (V1 main.py:6649 parity). Additive query param (refactor-plan §3.1). */
                wechat_sync_user_id?: string | null;
                /** @description Optional Feishu user id for dual-端 sync push. When provided, the AI reply is pushed to this Feishu user after stream completion (V1 main.py:6653 parity). Additive query param (refactor-plan §3.1). */
                feishu_sync_user_id?: string | null;
                /** @description Optional sub-agent session id. When present, this turn is a USER TAKE-OVER of that sub-agent: the turn continues the sub-agent's own persisted context (its prior messages + tool outputs) instead of the parent conversation, using the sub-agent tool set (no nested 'agent'). Additive query param (refactor-plan §3.1). */
                subagent_id?: string | null;
                /** @description Sub-agent take-over only: when True, the 'question' tool is advertised to the taken-over sub-agent so it can ask the user a blocking question (its dialog is reachable because the user has the sub-agent tab open and is conversing with it). Default False keeps 'question' excluded (matches the autonomous sub-agent tool set). Ignored on non-take-over turns. Additive query param (refactor-plan §3.1). */
                allow_question?: boolean;
                /** @description Main-agent turn only: when True, the first-level sub-agents this turn spawns are granted the 'agent' (spawn) tool so they may create their own (second-level / grand) sub-agents. Controls ONLY the main agent's direct children, not deeper levels. Default False keeps the historical hard recursion guard (sub-agents cannot spawn). Ignored on a sub-agent take-over turn. Additive query param (refactor-plan §3.1). */
                allow_child_spawn?: boolean;
                /** @description Sub-agent take-over only: when True, the 'agent' (spawn) tool is advertised to the taken-over sub-agent so it may create its own sub-agents. Independent of 'allow_child_spawn'. Default False keeps the autonomous sub-agent parity (no spawn). Ignored on non-take-over turns. Additive query param (refactor-plan §3.1). */
                self_allow_spawn?: boolean;
